import{_ as s,o as t,c as a,i as n}from"./chunks/framework.DP1yFSuu.js";const k=JSON.parse('{"title":"Tokens & Theming FAQ","description":"Common questions about token tiers, token files, theme bundles, dark mode, and token requests.","frontmatter":{"title":"Tokens & Theming FAQ","description":"Common questions about token tiers, token files, theme bundles, dark mode, and token requests."},"headers":[],"relativePath":"faqs/tokens-and-theming.md","filePath":"faqs/tokens-and-theming.md"}'),o={name:"faqs/tokens-and-theming.md"};function i(d,e,r,l,h,c){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="tokens-theming-faq" tabindex="-1">Tokens &amp; Theming FAQ <a class="header-anchor" href="#tokens-theming-faq" aria-label="Permalink to &quot;Tokens &amp; Theming FAQ&quot;">​</a></h1><p>These questions cover how Cobalt’s token system is organized and how theming works in both code and design handoff.</p><h2 id="should-i-use-primitive-semantic-or-component-tokens" tabindex="-1">Should I use primitive, semantic, or component tokens? <a class="header-anchor" href="#should-i-use-primitive-semantic-or-component-tokens" aria-label="Permalink to &quot;Should I use primitive, semantic, or component tokens?&quot;">​</a></h2><p>Use the highest-level token that accurately expresses the intent.</p><ul><li>Use <strong>semantic tokens</strong> first for product and component styling</li><li>Use <strong>primitive tokens</strong> when you are extending the underlying scales or palette</li><li>Use <strong>component tokens</strong> only when a value truly belongs to one component family</li></ul><p>That rule keeps raw values out of app code and lets themes change behavior through semantic remapping.</p><p>See <a href="/cobalt-design-system/tokens/structure.html">Token Structure</a> for the full decision tree.</p><h2 id="where-do-i-edit-tokens-and-where-do-i-consume-exports" tabindex="-1">Where do I edit tokens and where do I consume exports? <a class="header-anchor" href="#where-do-i-edit-tokens-and-where-do-i-consume-exports" aria-label="Permalink to &quot;Where do I edit tokens and where do I consume exports?&quot;">​</a></h2><p>Edit the source JSON files in <code>packages/tokens/tokens/*.json</code>.</p><p>Consume generated output from the published <code>@cobalt/tokens</code> package:</p><ul><li><code>@cobalt/tokens/css</code></li><li><code>@cobalt/tokens/themes/&lt;theme&gt;</code></li><li><code>@cobalt/tokens</code></li><li><code>@cobalt/tokens/json</code></li><li><code>@cobalt/tokens/dtcg</code></li></ul><p>Do not hand-edit generated <code>dist/</code> artifacts.</p><h2 id="what-is-tokens-merged-json-versus-tokens-dtcg-json" tabindex="-1">What is <code>tokens-merged.json</code> versus <code>tokens-dtcg.json</code>? <a class="header-anchor" href="#what-is-tokens-merged-json-versus-tokens-dtcg-json" aria-label="Permalink to &quot;What is `tokens-merged.json` versus `tokens-dtcg.json`?&quot;">​</a></h2><p>They serve different jobs:</p><ul><li><code>tokens-merged.json</code> is the Token Studio round-trip artifact</li><li><code>tokens-dtcg.json</code> is the more standards-aligned export for downstream consumers</li></ul><p>If you are syncing with Tokens Studio, use <code>tokens-merged.json</code>. If you need a DTCG-style export for tooling or interoperability, use <code>tokens-dtcg.json</code>.</p><h2 id="how-do-themes-and-dark-mode-work" tabindex="-1">How do themes and dark mode work? <a class="header-anchor" href="#how-do-themes-and-dark-mode-work" aria-label="Permalink to &quot;How do themes and dark mode work?&quot;">​</a></h2><p>Cobalt separates the base token layer from theme bundles.</p><p>Typical setup:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/css&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">;</span></span>\n<span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@import</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/themes/default&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">;</span></span></code></pre></div><p>Then switch at runtime with:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">import</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;"> { setTheme } </span><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">from</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;@cobalt/tokens/theme&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-dark:#DBB7FF;--shiki-light:#6F42C1;">setTheme</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">(</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;">&#39;default&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">, </span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;">&#39;dark&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">);</span></span>\n<span class="line"><span style="--shiki-dark:#DBB7FF;--shiki-light:#6F42C1;">setTheme</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">(</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;">&#39;purple&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">);</span></span></code></pre></div><p><code>setTheme()</code> updates <code>data-theme</code> and <code>data-mode</code> on <code>&lt;html&gt;</code>, which lets semantic color tokens swap without changing component code.</p><h2 id="when-should-i-request-a-new-token-instead-of-reusing-an-existing-one" tabindex="-1">When should I request a new token instead of reusing an existing one? <a class="header-anchor" href="#when-should-i-request-a-new-token-instead-of-reusing-an-existing-one" aria-label="Permalink to &quot;When should I request a new token instead of reusing an existing one?&quot;">​</a></h2><p>Request a new token when one of these is true:</p><ul><li>the value represents a reusable system rule</li><li>the value changes by theme or mode and current semantics cannot express it</li><li>the value belongs to a component family and would otherwise become a hardcoded exception</li></ul><p>Do not request a new token just because you found a raw value that is visually close to what you want. First check whether an existing semantic token already describes the intent.</p><h2 id="what-accessibility-standard-do-cobalt-token-and-theme-docs-assume" tabindex="-1">What accessibility standard do Cobalt token and theme docs assume? <a class="header-anchor" href="#what-accessibility-standard-do-cobalt-token-and-theme-docs-assume" aria-label="Permalink to &quot;What accessibility standard do Cobalt token and theme docs assume?&quot;">​</a></h2><p>The current formal docs claim is <strong>WCAG 2.1 AA</strong>.</p><p>That is the standard the FAQ and the normalized supporting docs should reference when talking about token contrast, component accessibility, and default design-system compliance.</p><h2 id="can-i-override-token-values-in-my-app" tabindex="-1">Can I override token values in my app? <a class="header-anchor" href="#can-i-override-token-values-in-my-app" aria-label="Permalink to &quot;Can I override token values in my app?&quot;">​</a></h2><p>Yes. Override token values, not token names.</p><p>Use subtree-scoped overrides when you want a local treatment, and root-level overrides when you want a global brand or application change. Keep the overrides semantic where possible so theme changes continue to work cleanly.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/cobalt-design-system/tokens/structure.html">Token Structure</a></li><li><a href="/cobalt-design-system/tokens/">Token Reference</a></li><li><a href="/cobalt-design-system/foundations/colors.html">Colors</a></li><li><a href="/cobalt-design-system/getting-started/developers.html">Getting Started for Developers</a></li></ul>',35)])])}const u=s(o,[["render",i]]);export{k as __pageData,u as default};
